from typing import Optional

def flatten(root: Optional['TreeNode']) -> None:
    if not root:
        return
    stack = [root]
    while stack:
        current = stack.pop()
        if current.right:
            stack.append(current.right)
        if current.left:
            stack.append(current.left)
        if stack:
            current.right = stack[-1]
